def apply_filter_rules(df):
    # [loop1] loop(rules)
    _rules = [{'categories': ['其他', '水渍', '异色', '焊丝', '脏污'], 'confidence_range': [0, 1], 'random_drop_ratio': 1}, {'categories': ['其他', '凹坑', '划伤', '压痕', '发亮', '异物外漏', '异色', '抛线', '拼接间隙', '擦伤', '断线', '未开孔', '杂质', '水渍', '漏墨', '焊丝', '爆线', '破损', '碰伤', '红标签', '纹理缺失', '线头', '缺料', '胶水', '脏污', '色差', '褶皱（重度）', '针眼', '飞边', '麻点', '鼓包'], 'confidence_range': [0, 0.25], 'random_drop_ratio': 1}]
    for _loop_rule in _rules:
        # [f1] filter
        if _loop_rule.get('confidence_mode') == 'min_threshold' or _loop_rule.get('min_confidence') is not None:
            df = strip_boxes_below_confidence(df, categories=_loop_rule.get('categories', []), min_confidence=float(_loop_rule.get('min_confidence', (_loop_rule.get('confidence_range') or [0, 1])[0])), positions=_loop_rule.get('positions') or None)
        else:
            df = filter_df_by_ext(df, categories=_loop_rule.get('categories', []), confidence_range=tuple(_loop_rule.get('confidence_range', [0, 1])), random_drop_ratio=_loop_rule.get('random_drop_ratio', 1.0), positions=_loop_rule.get('positions') or None)
    return df

